-- =============================================
-- K-edu teachers RLS 재설정 + contents 데이터 등록
-- 총 400건 | Supabase SQL Editor에서 실행
-- =============================================

-- 1. teachers RLS 재설정
ALTER TABLE teachers ENABLE ROW LEVEL SECURITY;

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='teachers' AND policyname='teachers_read_own') THEN
    CREATE POLICY "teachers_read_own" ON teachers FOR SELECT USING (user_id = auth.uid());
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='teachers' AND policyname='admins_read_all_teachers') THEN
    CREATE POLICY "admins_read_all_teachers" ON teachers FOR SELECT USING (EXISTS (SELECT 1 FROM teachers t WHERE t.user_id = auth.uid() AND t.is_admin = true));
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='teachers' AND policyname='teachers_insert_own') THEN
    CREATE POLICY "teachers_insert_own" ON teachers FOR INSERT WITH CHECK (user_id = auth.uid());
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='teachers' AND policyname='teachers_update_own') THEN
    CREATE POLICY "teachers_update_own" ON teachers FOR UPDATE USING (user_id = auth.uid());
  END IF;
END $$;

-- 2. contents 데이터 일괄 등록 (400건)

ON CONFLICT (file_path) DO UPDATE SET
  title=EXCLUDED.title, category=EXCLUDED.category, sub_category=EXCLUDED.sub_category,
  grade=EXCLUDED.grade, semester=EXCLUDED.semester, difficulty=EXCLUDED.difficulty, is_premium=EXCLUDED.is_premium;
